/* 架构示意图：ADC 精度链路四层设计 */

/* Layer 1: Analog Front-End Configuration */
// 输入通道配置 - 需根据信号源阻抗选择采样时间
// 信号源阻抗 < 1kΩ:   ADC_SAMPLETIME_3CYCLES (最快)
// 信号源阻抗 1k-10kΩ: ADC_SAMPLETIME_15CYCLES
// 信号源阻抗 > 10kΩ:  需加运放缓冲，否则用 ADC_SAMPLETIME_84CYCLES

/* Layer 2: ADC Core Configuration */
// VREF 去耦：100nF + 1μF 紧贴 VREF+ 引脚
// 差分模式启用（STM32H7）：
// hdca1.Init.DifferentialMode = ADC_DIFFERENTIAL_ENDEDUAL;

/* Layer 3: Digital Filtering - Oversampler */
// 配置过采样器提升有效分辨率
// RSMR.SAMPOT  = 6 (64 次累加)
// RSMR.OFFSET  = 0 (无偏移)
// RQR.AOFWDIS  = 1 (关闭模拟看门狗)
// RQR.AOVRMS   = 1 (启用累加模式)
// 右移位数: RSMR.DATMPX 决定移位量

/* Layer 4: System Calibration */
// 两点校准流程:
// 1. 输入 0V 读取 ADC_CODE_ZERO
// 2. 输入已知电压 Vin(如 2.500V) 读取 ADC_CODE_FULL
// 3. 计算: Gain = Vref_nominal / ((ADC_CODE_FULL - ADC_CODE_ZERO) * Vref_nominal / 4095)
// 4. 计算: Offset = ADC_CODE_ZERO * Gain
// 5. 实际值 = (Raw_Code - Offset) * Gain

/* STM32F429: ADC over-sampling config for 14-bit effective resolution */
/* ADC1, Channel 0 (PA0), DMA2 Stream 0 Channel 0 */

#define OVERSAMPLE_COUNT    64  /* 2^6 = 64 samples accumulated */
#define OVERSAMPLE_SHIFT    8   /* right-shift result by 8 bits */
#define ADC_CLOCK_DIV       4   /* HCLK(180MHz) / 4 = 45MHz ADC clock */

static uint32_t adc_over_sample_config(void)
{
    uint32_t accumulated = 0;
    uint32_t raw_value;

    /* Step 1: 启动 ADC 连续转换（非 DMA 模式用于演示单次读取）*/
    HAL_ADC_Start(&hadc1);

    /* Step 2: 累加 OVERSAMPLE_COUNT 次转换结果 */
    for (int i = 0; i < OVERSAMPLE_COUNT; i++) {
        /* 等待 EOC 标志位 - 超时保护防止死等 */
        if (HAL_ADC_PollForConversion(&hadc1, HAL_MAX_DELAY) != HAL_OK) {
            /* 超时处理：返回上次有效值，避免程序卡死 */
            return accumulated >> OVERSAMPLE_SHIFT;
        }
        raw_value = HAL_ADC_GetValue(&hadc1);  /* 读取 DR 寄存器 */
        accumulated += raw_value;
    }

    /* Step 3: 停止 ADC */
    HAL_ADC_Stop(&hadc1);

    /* Step 4: 右移获得过采样后的结果 */
    return accumulated >> OVERSAMPLE_SHIFT;
}

