/* 陷阱四修复：正确的内部温度传感器校准读取 */
#include "stm32f4xx_hal.h"

#define V25                   1.43f   /* TS 曲线在 25°C 时的典型电压 */
#define AVG_SLOPE             4.3f    /* mV/°C，TS 曲线的平均斜率 */
#define VREF_INT_CAL_ADDR     0x1FFF7A22U
#define VTEMP_CAL1_ADDR       0x1FFF7A24U

static float read_calibrated_temperature(void)
{
    /* Step 1: 读取出厂校准值 */
    uint16_t vref_cal = *(volatile uint16_t *)VREF_INT_CAL_ADDR;
    uint16_t temp_cal = *(volatile uint16_t *)VTEMP_CAL1_ADDR;

    /* Step 2: 配置 ADC 通道为内部温度传感器 */
    ADC_ChannelConfTypeDef sConfig = {0};
    sConfig.Channel = ADC_CHANNEL_TEMPSENSOR;
    sConfig.Rank = 1;
    sConfig.SamplingTime = ADC_SAMPLETIME_84CYCLES;
    HAL_ADC_ConfigChannel(&hadc1, &sConfig);

    /* Step 3: 读取当前温度传感器的 ADC 原始值 */
    HAL_ADC_Start(&hadc1);
    HAL_ADC_PollForConversion(&hadc1, 100);
    uint16_t vsense_raw = HAL_ADC_GetValue(&hadc1);
    HAL_ADC_Stop(&hadc1);

    /* Step 4: 转换为电压值 (mV) */
    float vsense_mv = (vsense_raw * 3300.0f) / 4095.0f;

    /* Step 5: 使用校准公式计算温度 */
    float temperature = ((V25 * 1000.0f - vsense_mv) / AVG_SLOPE) + 25.0f;

    return temperature;
}

/* 陷阱五修复：差分模式下的符号扩展正确处理 */
static int32_t read_differential_adc(void)
{
    HAL_ADC_Start(&hadc1);
    HAL_ADC_PollForConversion(&hadc1, 100);

    uint16_t ch0_raw = HAL_ADC_GetValue(&hadc1);
    uint16_t ch1_raw = HAL_ADC_GetValue(&hadc1);

    /* 使用有符号整数，右移时保持符号位 */
    int32_t diff = (int32_t)((int16_t)ch0_raw) - (int32_t)((int16_t)ch1_raw);

    /* 过采样累加（假设有符号累加器） */
    static int32_t acc = 0;
    acc += diff;

    /* 算术右移 - 对负数也能正确处理 */
    return acc >> 8;
}

/* ========== 改进前：轮询方式，CPU 被完全阻塞 ========== */
/* 坏味道1: 循环嵌套导致 CPU 利用率 100%
 * 坏味道2: 魔法数字 64 和 8 硬编码
 * 坏味道3: 无错误处理 */
uint16_t read_adc_polling(void)
{
    uint32_t sum = 0;
    for (int i = 0; i < 64; i++)  /* 魔法数字 */
    {
        HAL_ADC_Start(&hadc1);
        HAL_ADC_PollForConversion(&hadc1, HAL_MAX_DELAY);
        sum += HAL_ADC_GetValue(&hadc1);
    }
    HAL_ADC_Stop(&hadc1);
    return sum >> 8;  /* 魔法数字 */
}

/* ========== 改进后：DMA + 环形缓冲区 ========== */

#define RING_BUF_SIZE     128
#define OVERSAMPLE_N      64
#define OVERSAMPLE_SHIFT  8

typedef struct {
    uint16_t buffer[RING_BUF_SIZE];
    volatile uint16_t write_idx;
    volatile uint16_t read_idx;
    volatile uint8_t  data_ready;
} AdcRingBuffer_t;

static AdcRingBuffer_t adc_ring = {0};

/* DMA 传输完成回调 - 由 HAL 在中断中调用 */
void HAL_ADC_ConvCpltCallback(ADC_HandleTypeDef *hadc)
{
    /* 将 DMA 缓冲区中的数据写入环形缓冲区 */
    uint16_t *dma_buf = hadc->Instance == ADC1 ? adc_dma_buf : NULL;
    if (dma_buf == NULL) return;

    /* 非阻塞写入 - 如果缓冲区满则丢弃旧数据 */
    uint16_t next_write = (adc_ring.write_idx + 1) % RING_BUF_SIZE;
    if (next_write == adc_ring.read_idx) {
        /* 缓冲区已满，读取指针追上写入指针，丢弃最早的数据 */
        adc_ring.read_idx = (adc_ring.read_idx + 1) % RING_BUF_SIZE;
    }
    adc_ring.buffer[adc_ring.write_idx] = dma_buf[0];
    adc_ring.write_idx = next_write;
    adc_ring.data_ready = 1;
}

/* 从环形缓冲区读取并过采样计算 - 非阻塞 */
float read_adc_ring_buffer(void)
{
    if (!adc_ring.data_ready) return -1.0f;  /* 无数据 */

    uint32_t sum = 0;
    uint16_t idx = adc_ring.read_idx;

    /* 累加 OVERSAMPLE_N 个样本 */
    for (int i = 0; i < OVERSAMPLE_N; i++) {
        sum += adc_ring.buffer[idx];
        idx = (idx + 1) % RING_BUF_SIZE;
    }

    adc_ring.read_idx = idx;
    adc_ring.data_ready = 0;

    /* 转换为电压值 (mV) */
    return ((float)(sum >> OVERSAMPLE_SHIFT)) * 3300.0f / 4095.0f;
}
